// Pull attendees out of the incoming payload and attach event context to each.
// Ivybound pattern: flatten batch data before routing into splitInBatches.
const d = $input.first().json;
const event = d.event || {};
const sequence = d.sequence || {};
const attendees = d.attendees || [];

return attendees.map(a => ({
  json: {
    ...a,
    segment: sequence.segment || 'new_attendee',
    eventId: event.id,
    eventTitle: event.title,
    eventDate: event.event_date,
    rsvpUrl: (process.env.RSVP_URL_BASE || 'https://eoa.cm') + '/events/' + event.id,
    triggeredAt: d.triggered_at,
  }
}));

// Ivybound pattern: safely parse JSON from AI, fallback to plain text if malformed.
const d = $input.first().json;
const raw = d.message?.content || d.choices?.[0]?.message?.content || '';

let parsed = { subject: '', body: '' };
try {
  const clean = raw.replace(/^```json\n?/, '').replace(/\n?```$/, '').trim();
  parsed = JSON.parse(clean);
} catch (e) {
  const attendee = $('Loop – One Attendee at a Time').first().json;
  parsed.subject = `Great to see you at ${attendee.eventTitle}`;
  parsed.body = `<p>${raw}</p>`;
}

const attendee = $('Loop – One Attendee at a Time').first().json;
return [{ json: { ...attendee, emailSubject: parsed.subject, emailBody: parsed.body } }];
